// CreateFile is the resolver for the createFile field.
// MutationEventHook captures the mutation automatically.
func (r *mutationResolver) CreateFile(ctx context.Context, input ent.CreateFileInput) (*model.CreateFileResult, error) {
	dataType, err := r.validator.ValidateDataTypeInput(ctx, true, input.Data, input.DataTypeID, input.DataTypeSlug)
	if err != nil {
		return nil, err
	}

	mixin.PatchDataTypeIdSlugInput(&input, dataType)

	tx, err := gqltx.ForContext(ctx, ent.TxFromContext)
	if err != nil {
		return nil, err
	}

	file, err := tx.File.Create().
		SetInput(input).
		Save(ctx)
	if err != nil {
		return nil, err
	}

	if err = r.validator.ValidateInputDataUniqueness(ctx, tx, validator.UniquenessValidationParams{
		Input:     input.Data,
		DataType:  dataType,
		TableName: entfile.Table,
		FieldName: entfile.FieldData,
		DbDriver:  core.Config.DbDriver,
	}); err != nil {
		return nil, err
	}

	preSignedUploadURL, err := r.s3Storage.GetPreSignedUploadURL(file.TenantID, file.Name, file.Refid, file.ContentType)
	if err != nil {
		return nil, err
	}

	return &model.CreateFileResult{
		ID:                 file.ID,
		PreSignedUploadURL: &preSignedUploadURL,
		File:               file,
	}, nil
}

